import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const normalized = condition.toLowerCase().trim();

  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('night') || normalized.includes('dark')) return '🌙';
  if (normalized.includes('partly')) return '⛅';

  return '🌤️'; // default
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  const emoji = getWeatherEmoji(condition);

  return (
    <Card padding={24} shadow="md">
      <Stack direction="vertical" gap={24}>
        {/* Current Weather Header */}
        <Stack direction="vertical" gap={8}>
          <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
            {city}
          </Text>
        </Stack>

        {/* Temperature Section */}
        <Stack direction="vertical" gap={16} align="center">
          <Text
            variant="h1"
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: '1',
              margin: '0',
            }}
          >
            {temperature}°{unit}
          </Text>
          <Row gap={12} align="center" justify="center">
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-3xl, 30px)',
                margin: '0',
              }}
            >
              {emoji}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-600, #4b5563)"
              style={{
                fontSize: 'var(--ggui-font-size-lg, 18px)',
              }}
            >
              {condition}
            </Text>
          </Row>
        </Stack>

        {/* Weather Details */}
        <Row gap={32} justify="center" align="stretch">
          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              align="center"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              align="center"
            >
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              align="center"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              align="center"
            >
              {windSpeed} {unit === 'F' ? 'mph' : 'kph'}
            </Text>
          </Stack>
        </Row>

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-neutral-700, #374151)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>
          <Row gap={8} justify="between" align="stretch" wrap>
            {forecast.slice(0, 5).map((day, index) => (
              <Box
                key={index}
                style={{
                  flex: '1 1 calc(20% - 7px)',
                  minWidth: '80px',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  textAlign: 'center',
                }}
              >
                <Stack direction="vertical" gap={6} align="center">
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-neutral-700, #374151)"
                  >
                    {day.day}
                  </Text>
                  <Text style={{ fontSize: 'var(--ggui-font-size-lg, 18px)', margin: '0' }}>
                    {day.icon}
                  </Text>
                  <Stack direction="horizontal" gap={4} justify="center">
                    <Text
                      variant="caption"
                      weight="semibold"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      {day.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
